module RefModule(  
    input wire clk,  
    input wire reset,  
    input wire [23:0] adc_input,  
    input wire [23:0] threshold,  
    output reg exceed_threshold  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            exceed_threshold <= 0;  
        else  
            exceed_threshold <= (adc_input > threshold) ? 1 : 0;  
    end  
endmodule
